# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import json

def lambda_handler(event, context):
    # Database connection configuration
    db_config = {
        'host': 'your-rds-endpoint',
        'user': 'your-username',
        'password': 'your-password',
        'database': 'your-database-name'
    }
    
    # Connect to the database
    try:
        conn = pymysql.connect(**db_config)
        cursor = conn.cursor()
    except pymysql.MySQLError as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': f'Database connection failed: {str(e)}'})
        }
    
    # Extract search parameters from the API Gateway event
    params = event.get('queryStringParameters', {})
    
    # Construct the SQL query dynamically based on the provided parameters
    base_query = "SELECT * FROM products WHERE 1=1"
    conditions = []
    values = []
    
    if 'name' in params:
        conditions.append("name LIKE %s")
        values.append(f"%{params['name']}%")
        
    if 'category' in params:
        conditions.append("category = %s")
        values.append(params['category'])
        
    if 'price_min' in params:
        conditions.append("price >= %s")
        values.append(float(params['price_min']))
        
    if 'price_max' in params:
        conditions.append("price <= %s")
        values.append(float(params['price_max']))
    
    # Combine conditions into a single query
    if conditions:
        full_query = base_query + " AND " + " AND ".join(conditions)
    else:
        full_query = base_query
    
    # Execute the query
    try:
        cursor.execute(full_query, values)
        results = cursor.fetchall()
        
        # Convert results to a list of dictionaries for JSON serialization
        columns = [desc[0] for desc in cursor.description]
        products = [dict(zip(columns, row)) for row in results]
        
        return {
            'statusCode': 200,
            'body': json.dumps({'products': products})
        }
    except pymysql.MySQLError as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': f'Query execution failed: {str(e)}'})
        }
    finally:
        cursor.close()
        conn.close()